import{_ as a,o,c as t,au as s}from"./chunks/framework.Bpqx6pAq.js";const m=JSON.parse('{"title":"Composables","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/composables.md","filePath":"api/map/composables.md"}'),r={name:"api/map/composables.md"};function i(c,e,l,h,n,p){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="composables" tabindex="-1">Composables <a class="header-anchor" href="#composables" aria-label="Permalink to &quot;Composables&quot;">​</a></h1><h2 id="activity" tabindex="-1">Activity <a class="header-anchor" href="#activity" aria-label="Permalink to &quot;Activity&quot;">​</a></h2><h3 id="useactivity-usecurrentactivity" tabindex="-1"><a href="./composables/composables.activity.html">useActivity / useCurrentActivity</a> <a class="header-anchor" href="#useactivity-usecurrentactivity" aria-label="Permalink to &quot;[useActivity / useCurrentActivity](./composables/composables.activity.md)&quot;">​</a></h3><ul><li><strong><code>useActivity(name, options)</code></strong> — extends the core activity composable with map-specific sub-stores (selection, probe, highlight).</li><li><strong><code>useCurrentActivity(options)</code></strong> — retrieves the current map activity context, including project and all map-specific state.</li></ul><h2 id="selection" tabindex="-1">Selection <a class="header-anchor" href="#selection" aria-label="Permalink to &quot;Selection&quot;">​</a></h2><h3 id="useselection" tabindex="-1"><a href="./composables/composables.selection.html">useSelection</a> <a class="header-anchor" href="#useselection" aria-label="Permalink to &quot;[useSelection](./composables/composables.selection.md)&quot;">​</a></h3><p>Extends the core <a href="./../core/composables/composables.selection.html">selection composable</a> with map-specific behaviour: click, box, and cluster selection handlers; real-time feature tracking via service events; and helper functions for accessing selected features, layers, and locations.</p><h2 id="probe" tabindex="-1">Probe <a class="header-anchor" href="#probe" aria-label="Permalink to &quot;Probe&quot;">​</a></h2><h3 id="useprobe" tabindex="-1"><a href="./composables/composables.probe.html">useProbe</a> <a class="header-anchor" href="#useprobe" aria-label="Permalink to &quot;[useProbe](./composables/composables.probe.md)&quot;">​</a></h3><p>Sets up a reactive store for probing at a specific map location or feature. Registers a click handler to capture probe targets and exposes helpers to inspect, navigate to, and clear the probed location.</p><h2 id="highlight" tabindex="-1">Highlight <a class="header-anchor" href="#highlight" aria-label="Permalink to &quot;Highlight&quot;">​</a></h2><h3 id="usehighlight" tabindex="-1"><a href="./composables/composables.highlight.html">useHighlight</a> <a class="header-anchor" href="#usehighlight" aria-label="Permalink to &quot;[useHighlight](./composables/composables.highlight.md)&quot;">​</a></h3><p>Manages a reactive store of map highlights — styled GeoJSON features rendered in a dedicated system layer on top of the map. Keeps highlights in sync with real-time service events and layer visibility changes.</p><h2 id="project" tabindex="-1">Project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;Project&quot;">​</a></h2><h3 id="useproject" tabindex="-1"><a href="./composables/composables.project.html">useProject</a> <a class="header-anchor" href="#useproject" aria-label="Permalink to &quot;[useProject](./composables/composables.project.md)&quot;">​</a></h3><p>Manages a map project loaded from the <code>projects</code> service. Can track the project ID from the route query parameter or load it manually, and keeps the local project in sync with real-time updates.</p><h2 id="catalog" tabindex="-1">Catalog <a class="header-anchor" href="#catalog" aria-label="Permalink to &quot;Catalog&quot;">​</a></h2><h3 id="usecatalog" tabindex="-1"><a href="./composables/composables.catalog.html">useCatalog</a> <a class="header-anchor" href="#usecatalog" aria-label="Permalink to &quot;[useCatalog](./composables/composables.catalog.md)&quot;">​</a></h3><p>Provides reactive access to catalog data (layers, categories, sublegends, views). Exposes async fetch functions and computed properties organizing layers by category and identifying orphan layers.</p><h2 id="location" tabindex="-1">Location <a class="header-anchor" href="#location" aria-label="Permalink to &quot;Location&quot;">​</a></h2><h3 id="uselocation" tabindex="-1"><a href="./composables/composables.location.html">useLocation</a> <a class="header-anchor" href="#uselocation" aria-label="Permalink to &quot;[useLocation](./composables/composables.location.md)&quot;">​</a></h3><p>Provides reactive geocoder configuration and location search capabilities. Integrates with the KDK <code>Geocoder</code> and <code>Geolocation</code> services with optional filtering based on the current activity project.</p><h2 id="measure" tabindex="-1">Measure <a class="header-anchor" href="#measure" aria-label="Permalink to &quot;Measure&quot;">​</a></h2><h3 id="usemeasure" tabindex="-1"><a href="./composables/composables.measure.html">useMeasure</a> <a class="header-anchor" href="#usemeasure" aria-label="Permalink to &quot;[useMeasure](./composables/composables.measure.md)&quot;">​</a></h3><p>Provides helper functions to extract measurement values at the current application time from time-series data attached to probed features, using nearest-time interpolation.</p><h2 id="weather" tabindex="-1">Weather <a class="header-anchor" href="#weather" aria-label="Permalink to &quot;Weather&quot;">​</a></h2><h3 id="useweather" tabindex="-1"><a href="./composables/composables.weather.html">useWeather</a> <a class="header-anchor" href="#useweather" aria-label="Permalink to &quot;[useWeather](./composables/composables.weather.md)&quot;">​</a></h3><p>Provides helpers for working with Weacast weather forecast data: resolving forecast field paths, formatting forecast HTML, and creating Leaflet wind barb markers and tooltips.</p>',28)])])}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
